mapper.select:
select 
from document_artifact
where trace_id = #{traceId}
  and artifact_type = #{artifactType}
order by sort_no asc, created_at asc

select 
from document_artifact
where task_id = #{taskId}
  and artifact_type = #{artifactType}
order by sort_no asc, created_at asc

mapper.insert:
insert into document_artifact (
    id, trace_id, task_id, document_id, parent_id, artifact_type, stage_code,
    file_name, file_ext, mime_type, storage_path, preview_path, file_size,
    checksum, page_no, page_range, sort_no, status, metadata_json, created_at, updated_at
) values (
    #{id}, #{traceId}, #{taskId}, #{documentId}, #{parentId}, #{artifactType}, #{stageCode},
    #{fileName}, #{fileExt}, #{mimeType}, #{storagePath}, #{previewPath}, #{fileSize},
    #{checksum}, #{pageNo}, #{pageRange}, #{sortNo}, #{status}, #{metadataJson}, #{createdAt}, #{updatedAt}
)

mapper.select:
select 
from document_artifact_step
where task_id = #{taskId}
  and step_code = #{stepCode}

mapper.insert:
insert into document_artifact_step (
    id, trace_id, task_id, step_code, step_name, step_type, input_artifact_ids,
    output_artifact_ids, config_json, status, error_message, started_at, ended_at,
    duration_ms, created_at
) values (
    #{id}, #{traceId}, #{taskId}, #{stepCode}, #{stepName}, #{stepType}, #{inputArtifactIds},
    #{outputArtifactIds}, #{configJson}, #{status}, #{errorMessage}, #{startedAt}, #{endedAt},
    #{durationMs}, #{createdAt}
)
